3447 static InstLane lookThroughShuffles(Use *U, int Lane) {
3448   while (auto *SV = dyn_cast<ShuffleVectorInst>(U->get())) {
3449     unsigned NumElts =
3450         cast<FixedVectorType>(SV->getOperand(0)->getType())->getNumElements();
3451     int M = SV->getMaskValue(Lane);
3452     if (M < 0)
3453       return {nullptr, PoisonMaskElem};
3454     if (static_cast<unsigned>(M) < NumElts) {
3455       U = &SV->getOperandUse(0);
3456       Lane = M;
3457     } else {
3458       U = &SV->getOperandUse(1);
3459       Lane = M - NumElts;
3460     }
3461   }
3462   return InstLane{U, Lane};
3463 }
