5627 /// Find the earliest point where both V0 and V1 are available
5628 /// This ensures the created shuffle will dominate all its uses
5629 Instruction *VectorCombine::findEarliestInsertionPoint(Value *V0, Value *V1) {
5630   Instruction *I0 = dyn_cast<Instruction>(V0);
5631   Instruction *I1 = dyn_cast<Instruction>(V1);
5632 
5633   // Not an instruction = available from entry
5634   // (includes constants, arguments, globals, functions)
5635   if (!I0 && !I1) {
5636     return &*F.getEntryBlock().getFirstInsertionPt();
5637   }
5638 
5639   if (!I0) { // V0 is not instruction, V1 is instruction
5640     BasicBlock::iterator It(I1);
5641     return &*(++It);
5642   }
5643 
5644   if (!I1) { // V1 is not instruction, V0 is instruction
5645     BasicBlock::iterator It(I0);
5646     return &*(++It);
5647   }
5648 
5649   // Both are instructions, same block
5650   if (I0->getParent() == I1->getParent()) {
5651     Instruction *Later = I0->comesBefore(I1) ? I1 : I0;
5652     BasicBlock::iterator It(Later);
5653     return &*(++It);
5654   }
5655 
5656   // Different blocks, fallback to current insertion point
5657   return &*Builder.GetInsertPoint();
